import sys
import itertools

def find(parent, x):
    if parent[x] != x:
        parent[x] = find(parent, parent[x])
    return parent[x]

def union(parent, rank, x, y):
    x_root = find(parent, x)
    y_root = find(parent, y)
    if x_root == y_root:
        return False
    if rank[x_root] < rank[y_root]:
        parent[x_root] = y_root
    else:
        parent[y_root] = x_root
        if rank[x_root] == rank[y_root]:
            rank[x_root] += 1
    return True

def kruskal(n, edges):
    edges = sorted(edges, key=lambda x: x[2])
    parent = list(range(n + 1))
    rank = [0] * (n + 1)
    total_weight = 0
    for u, v, w in edges:
        if union(parent, rank, u, v):
            total_weight += w
    return total_weight

def main():
    input = sys.stdin.read().split()
    idx = 0
    N = int(input[idx]); idx += 1
    M = int(input[idx]); idx += 1
    K = int(input[idx]); idx += 1
    edges = []
    for _ in range(M):
        u = int(input[idx]); idx += 1
        v = int(input[idx]); idx += 1
        w = int(input[idx]); idx += 1
        edges.append((u, v, w))
    # Generate all possible spanning trees
    min_cost = K  # Initialize with maximum possible value
    for subset in itertools.combinations(edges, N - 1):
        parent = list(range(N + 1))
        rank = [0] * (N + 1)
        is_tree = True
        for u, v, _ in subset:
            if find(parent, u) == find(parent, v):
                is_tree = False
                break
            union(parent, rank, u, v)
        if is_tree:
            total_weight = sum(w for _, _, w in subset)
            cost = total_weight % K
            if cost < min_cost:
                min_cost = cost
    print(min_cost)

if __name__ == "__main__":
    main()
